import{c as o,Z as p,Q as r,j as n,g as a,n as s,o as i,m as l}from"./chunks/framework.qjzPVSkb.js";const k=JSON.parse('{"title":"什么是 Prompt","description":"理解 Prompt 的本质——你给 AI 的指令，输入的质量决定输出的质量","frontmatter":{"title":"什么是 Prompt","description":"理解 Prompt 的本质——你给 AI 的指令，输入的质量决定输出的质量","difficulty":"beginner"},"headers":[],"relativePath":"prompts/what-is-prompt.md","filePath":"prompts/what-is-prompt.md"}'),d={name:"prompts/what-is-prompt.md"},h={id:"什么是-prompt",tabindex:"-1"};function m(c,t,u,b,g,P){const e=p("DifficultyBadge");return r(),n("div",null,[a("h1",h,[t[0]||(t[0]=s("什么是 Prompt ",-1)),i(e,{level:"beginner"}),t[1]||(t[1]=s()),t[2]||(t[2]=a("a",{class:"header-anchor",href:"#什么是-prompt","aria-label":'Permalink to "什么是 Prompt <DifficultyBadge level="beginner" />"'},"​",-1))]),t[3]||(t[3]=l(`<p><strong>Prompt（提示词）</strong> 就是你给 AI 的输入指令。无论是一句话、一段文字，还是一个完整的结构化文档，都是 Prompt。</p><blockquote><p>核心理念：<strong>输入的质量，决定输出的质量。</strong></p></blockquote><hr><h2 id="prompt-的三种角色" tabindex="-1">Prompt 的三种角色 <a class="header-anchor" href="#prompt-的三种角色" aria-label="Permalink to &quot;Prompt 的三种角色&quot;">​</a></h2><p>在一次完整的对话中，Prompt 通常包含三种角色：</p><table tabindex="0"><thead><tr><th>角色</th><th>说明</th><th>谁写的</th></tr></thead><tbody><tr><td><strong>System Prompt</strong></td><td>系统级指令，设定 AI 的行为基调</td><td>开发者 / 你（API 调用时）</td></tr><tr><td><strong>User Prompt</strong></td><td>你直接发给 AI 的问题或指令</td><td>你</td></tr><tr><td><strong>Assistant</strong></td><td>AI 之前的回复（多轮对话时传递）</td><td>AI</td></tr></tbody></table><p>这三种角色共同构成了 <a href="/ai-knowledge/terms/llm.html">LLM</a> 的上下文。</p><hr><h2 id="好-prompt-vs-坏-prompt" tabindex="-1">好 Prompt vs 坏 Prompt <a class="header-anchor" href="#好-prompt-vs-坏-prompt" aria-label="Permalink to &quot;好 Prompt vs 坏 Prompt&quot;">​</a></h2><p>同样是让 AI 写一份产品介绍，Prompt 的质量差异巨大：</p><h3 id="❌-坏-prompt" tabindex="-1">❌ 坏 Prompt <a class="header-anchor" href="#❌-坏-prompt" aria-label="Permalink to &quot;❌ 坏 Prompt&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>写个产品介绍。</span></span></code></pre></div><p>AI 不知道：什么产品？给谁看？多长？什么风格？结果大概率是泛泛而谈。</p><h3 id="✅-好-prompt" tabindex="-1">✅ 好 Prompt <a class="header-anchor" href="#✅-好-prompt" aria-label="Permalink to &quot;✅ 好 Prompt&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是一位产品营销专家。我们需要为一款名为&quot;智记&quot;的 AI 笔记应用写一段产品介绍。</span></span>
<span class="line"><span>目标用户是大学生和白领，文案风格轻松活泼，字数 150 字左右。</span></span>
<span class="line"><span>重点突出三个功能：语音转文字、AI 自动摘要、跨设备同步。</span></span></code></pre></div><p>提供的信息越多，AI 的输出越精准。</p><hr><h2 id="好-prompt-的三个要素" tabindex="-1">好 Prompt 的三个要素 <a class="header-anchor" href="#好-prompt-的三个要素" aria-label="Permalink to &quot;好 Prompt 的三个要素&quot;">​</a></h2><ol><li><strong>清晰</strong> — 指令不模糊，AI 不需要猜测你的意图</li><li><strong>具体</strong> — 有具体要求和约束条件，而不是开放式的&quot;随便写&quot;</li><li><strong>有上下文</strong> — 告诉 AI 背景信息、目标用户、使用场景</li></ol><hr><h2 id="对比示例-翻译任务" tabindex="-1">对比示例：翻译任务 <a class="header-anchor" href="#对比示例-翻译任务" aria-label="Permalink to &quot;对比示例：翻译任务&quot;">​</a></h2><h3 id="❌-模糊指令" tabindex="-1">❌ 模糊指令 <a class="header-anchor" href="#❌-模糊指令" aria-label="Permalink to &quot;❌ 模糊指令&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>翻译成英文。</span></span></code></pre></div><h3 id="✅-清晰指令" tabindex="-1">✅ 清晰指令 <a class="header-anchor" href="#✅-清晰指令" aria-label="Permalink to &quot;✅ 清晰指令&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请将以下中文翻译成英文，要求：</span></span>
<span class="line"><span>- 保持原文语气（正式商务风格）</span></span>
<span class="line"><span>- 使用英式拼写</span></span>
<span class="line"><span>- 翻译后附上 1-2 句翻译说明</span></span>
<span class="line"><span></span></span>
<span class="line"><span>原文：我们致力于为客户提供一站式数字化解决方案。</span></span></code></pre></div><hr><h2 id="进阶阅读" tabindex="-1">进阶阅读 <a class="header-anchor" href="#进阶阅读" aria-label="Permalink to &quot;进阶阅读&quot;">​</a></h2><ul><li><a href="./principles.html">清晰指令五原则</a> — 五条核心原则，每条配对比示例</li><li><a href="./structured-prompt.html">结构化提示词</a> — 用 Markdown/XML 组织复杂 Prompt</li><li><a href="/ai-knowledge/terms/llm.html">什么是 LLM？</a> — 理解背后的模型</li></ul>`,28))])}const v=o(d,[["render",m]]);export{k as __pageData,v as default};
